args.sparql:
SELECT (COUNT(*) AS ?count) WHERE {
  ?event wdt:P31 wd:Q3702313 ;
         rdfs:label "Tour de Pologne"@en ;
         wdt:P585 ?date .
  BIND(YEAR(?date) AS ?year) .
  FILTER (?year = 2006)

  ?event p:P170 ?participant_statement .
  ?participant_statement ps:P170 ?cyclist ;
                  pq:P2586 ?time_diff .
  FILTER (?time_diff < "PT30M"^^xsd:duration)

  ?cyclist p:P1510 ?grand_tour_participation .
  ?grand_tour_participation ps:P1510 ?grand_tour ;
                           ps:P170 ?rank .
  ?grand_tour wdt:P31 wd:Q3702313 .
  VALUES ?grand_tour { wd:Q673588 wd:Q158 wd:Q3062388 }
  FILTER (?rank <= 10)
}

